const entrada = $("Procesar una URL por vez").item.json;
const respuesta = $json;
const headers = respuesta.headers ?? {};
const contentType = String(
  headers["content-type"] ??
  headers["Content-Type"] ??
  respuesta.contentType ??
  ""
).toLowerCase();
const httpStatus = Number(respuesta.statusCode ?? respuesta.status ?? 200);
const body =
  typeof respuesta.body === "string"
    ? respuesta.body
    : typeof respuesta.data === "string"
      ? respuesta.data
      : typeof respuesta === "string"
        ? respuesta
        : "";
const sourceUrl = String(entrada.source_url ?? "");
let source;
try {
  source = new URL(sourceUrl);
} catch {
  return [{ json: { ...entrada, status: "skipped", razon: "La URL de origen no es válida." } }];
}
const host = source.hostname.replace(/^www\./, "").toLowerCase();
if (host === "speeches.byu.edu" && !source.pathname.startsWith("/spa/talks/")) {
  return [{ json: { ...entrada, status: "skipped", razon: "BYU Speeches solo admite discursos bajo /spa/talks/." } }];
}
if (host === "churchofjesuschrist.org" && source.searchParams.get("lang") !== "spa") {
  return [{ json: { ...entrada, status: "skipped", razon: "La página oficial no declara lang=spa." } }];
}
const parecePdf =
  contentType.includes("application/pdf") ||
  /\.pdf(?:$|[?#])/i.test(sourceUrl) ||
  body.startsWith("%PDF-");
const pareceHtml =
  contentType.includes("text/html") ||
  /<(?:html|body|main|article|h1|p)\b/i.test(body);

if (httpStatus >= 400) {
  return [{
    json: {
      ...entrada,
      status: "skipped",
      tipo_recurso: "desconocido",
      razon: `La fuente respondió HTTP ${httpStatus}.`,
      http_status: httpStatus
    }
  }];
}

if (parecePdf) {
  return [{
    json: {
      ...entrada,
      status: "skipped",
      tipo_recurso: "pdf",
      content_type: "application/pdf",
      razon: "skipped_pdf_pending: la extracción de PDF no está habilitada en este workflow.",
      http_status: httpStatus
    }
  }];
}

if (!pareceHtml) {
  return [{
    json: {
      ...entrada,
      status: "skipped",
      tipo_recurso: "desconocido",
      razon: "El recurso no parece HTML ni PDF.",
      http_status: httpStatus
    }
  }];
}

return [{
  json: {
    ...entrada,
    status: "html_detectado",
    tipo_recurso: "html",
    content_type: "text/html",
    raw_html: body,
    http_status: httpStatus
  }
}];

function decodeEntities(value) {
  const named = {
    amp: "&",
    apos: "'",
    gt: ">",
    ldquo: "\"",
    lsquo: "'",
    lt: "<",
    nbsp: " ",
    ndash: "-",
    mdash: "-",
    quot: "\"",
    rdquo: "\"",
    rsquo: "'"
  };
  return value
    .replace(/&#(\d+);/g, (_, code) => String.fromCodePoint(Number(code)))
    .replace(/&#x([0-9a-f]+);/gi, (_, code) => String.fromCodePoint(parseInt(code, 16)))
    .replace(/&([a-z]+);/gi, (match, name) => named[name.toLowerCase()] ?? match);
}

function normalizarTextoEspanol(value, conservarSaltos = false) {
  let texto = decodeEntities(String(value ?? ""));
  const cp1252 = { "€": 0x80, "‚": 0x82, "ƒ": 0x83, "„": 0x84, "…": 0x85, "†": 0x86, "‡": 0x87, "ˆ": 0x88, "‰": 0x89, "Š": 0x8a, "‹": 0x8b, "Œ": 0x8c, "Ž": 0x8e, "‘": 0x91, "’": 0x92, "“": 0x93, "”": 0x94, "•": 0x95, "–": 0x96, "—": 0x97, "˜": 0x98, "™": 0x99, "š": 0x9a, "›": 0x9b, "œ": 0x9c, "ž": 0x9e, "Ÿ": 0x9f };
  for (let intento = 0; intento < 3 && /Ã|Â|â€|â€™|â€œ|â€�/.test(texto); intento += 1) {
    if ([...texto].some((caracter) => caracter.codePointAt(0) > 255 && cp1252[caracter] === undefined)) break;
    try {
      const bytes = Uint8Array.from([...texto], (caracter) => cp1252[caracter] ?? caracter.charCodeAt(0));
      const reparado = new TextDecoder("utf-8", { fatal: true }).decode(bytes);
      if (reparado === texto) break;
      texto = reparado;
    } catch {
      break;
    }
  }
  texto = texto.replace(/\u00a0/g, " ").replace(/\u200b/g, "").replace(/Â(?=\s|$)/g, "").normalize("NFC");
  if (conservarSaltos) {
    return texto
      .split(/\r?\n/)
      .map((linea) => linea.replace(/[^\S\n]+/g, " ").trim())
      .join("\n")
      .replace(/\n{3,}/g, "\n\n")
      .trim();
  }
  return texto.replace(/\s+/g, " ").trim();
}

function firstMatch(html, patterns) {
  for (const pattern of patterns) {
    const match = html.match(pattern);
    if (match?.[1]) return normalizarTextoEspanol(match[1].replace(/<[^>]+>/g, " "));
  }
  return null;
}

function canonicalFrom(html, fallback) {
  const links = html.match(/<link\b[^>]*>/gi) ?? [];
  for (const link of links) {
    if (!/\brel\s*=\s*["'][^"']*canonical/i.test(link)) continue;
    const href = link.match(/\bhref\s*=\s*["']([^"']+)["']/i)?.[1];
    if (href) {
      try {
        return new URL(decodeEntities(href), fallback).toString();
      } catch {
        return fallback;
      }
    }
  }
  return fallback;
}

function authorFrom(html) {
  const metaTags = html.match(/<meta\b[^>]*>/gi) ?? [];
  for (const tag of metaTags) {
    if (!/\b(?:name|property)\s*=\s*["'](?:author|article:author|citation_author)["']/i.test(tag)) continue;
    const content = tag.match(/\bcontent\s*=\s*["']([^"']+)["']/i)?.[1];
    if (content) {
      const candidate = decodeEntities(content)
        .replace(/^por\s+/i, "")
        .replace(/^(?:el|la)\s+/i, "")
        .trim();
      if (!/(?:anónimo|desconocido|dice:|comentario)/i.test(candidate)) return candidate;
    }
  }
  const candidate = firstMatch(html, [
    /<(?:strong|b)[^>]*>\s*(?:por el|por la|por)\s+([^<]{3,120})<\/(?:strong|b)>/i,
    /<(?:p|div|span)[^>]+class=["'][^"']*(?:byline|speaker)[^"']*["'][^>]*>([\s\S]*?)<\/(?:p|div|span)>/i
  ]);
  return candidate && !/(?:anónimo|desconocido|dice:|comentario)/i.test(candidate)
    ? candidate.replace(/^(?:por\s+)?(?:el|la)\s+/i, "").trim()
    : null;
}

const item = $json;
if (item.status === "skipped") {
  return [{ json: item }];
}

const htmlOriginal = String(item.raw_html ?? "");
const title = firstMatch(htmlOriginal, [
  /<h1\b[^>]*>([\s\S]*?)<\/h1>/i,
  /<title\b[^>]*>([\s\S]*?)<\/title>/i
]);
const canonicalUrl = canonicalFrom(htmlOriginal, item.source_url);
const author = authorFrom(htmlOriginal);

let html = htmlOriginal
  .replace(/<!--[\s\S]*?-->/g, " ")
  .replace(/<(script|style|nav|footer|header|aside|noscript|form|svg|button)\b[^>]*>[\s\S]*?<\/\1>/gi, " ");

const principal =
  html.match(/<article\b[^>]*>([\s\S]*?)<\/article>/i)?.[1] ??
  html.match(/<main\b[^>]*>([\s\S]*?)<\/main>/i)?.[1] ??
  html.match(/<body\b[^>]*>([\s\S]*?)<\/body>/i)?.[1] ??
  html;

const lineas = decodeEntities(
  principal
    .replace(/<(br|\/p|\/li|\/h[1-6]|\/blockquote|\/section|\/div)>/gi, "\n")
    .replace(/<[^>]+>/g, " ")
)
  .split(/\n+/)
  .map((linea) => linea.replace(/\s+/g, " ").trim())
  .filter((linea) => linea.length >= 20);

const vistas = new Set();
const basura = /^(inicio|menú|buscar|compartir|descargar|siguiente|anterior|todos los derechos|privacy|cookies?)\b/i;
const contenido = lineas
  .filter((linea) => {
    const key = linea.toLowerCase();
    if (basura.test(linea) || vistas.has(key)) return false;
    vistas.add(key);
    return true;
  })
  .join("\n\n")
  .trim();

return [{
  json: {
    ...item,
    status: "contenido_extraido",
    title: normalizarTextoEspanol(title ?? item.title ?? ""),
    author: normalizarTextoEspanol(author ?? item.author ?? "") || null,
    source_name: normalizarTextoEspanol(item.source_name ?? ""),
    canonical_url: canonicalUrl,
    content: normalizarTextoEspanol(contenido, true),
    extracted_at: new Date().toISOString(),
    extractor_version: "n8n-html-regex-v1",
    raw_html: undefined
  }
}];

const item = $json;
if (item.status === "skipped") {
  return [{ json: item }];
}

const texto = String(item.content ?? "").trim();
const palabras = (texto.toLowerCase().match(/[a-záéíóúüñ]+/g) ?? []);
const marcadoresEs = new Set([
  "al", "como", "con", "cristo", "de", "del", "dios", "el", "en", "es",
  "evangelio", "jesucristo", "la", "las", "los", "para", "por", "que",
  "se", "su", "una", "y"
]);
const marcadoresEn = new Set([
  "and", "are", "christ", "for", "from", "god", "is", "jesus", "of", "that",
  "the", "this", "to", "was", "with", "you"
]);
const cuentaEs = palabras.filter((palabra) => marcadoresEs.has(palabra)).length;
const cuentaEn = palabras.filter((palabra) => marcadoresEn.has(palabra)).length;
const proporcionEs = palabras.length ? cuentaEs / palabras.length : 0;
const basuraNavegacion = (
  texto.match(/\b(inicio|menú|buscar|compartir|suscríbete|cookies?|privacidad|siguiente|anterior)\b/gi) ?? []
).length;

let razon = null;
if (!item.title || String(item.title).trim().length < 3) {
  razon = "No se pudo extraer un título confiable.";
} else if (texto.length < 301) {
  razon = "El texto limpio tiene menos de 301 caracteres.";
} else if (palabras.length < 60) {
  razon = "El documento contiene muy pocas palabras útiles.";
} else if (cuentaEs < 8 || proporcionEs < 0.025 || cuentaEn > cuentaEs) {
  razon = "La heurística no pudo confirmar que el contenido esté en español.";
} else if (basuraNavegacion > 12) {
  razon = "El contenido parece contener navegación o texto repetido.";
}

if (razon) {
  return [{
    json: {
      ...item,
      status: "skipped",
      razon,
      content: undefined
    }
  }];
}

return [{
  json: {
    ...item,
    status: "ready",
    language: "es",
    content: texto,
    validacion: {
      caracteres: texto.length,
      palabras: palabras.length,
      marcadores_es: cuentaEs,
      marcadores_en: cuentaEn
    }
  }
}];

const item = $json;
if (item.status !== "ready") {
  return [{ json: item }];
}

function normalizarTextoEspanol(value, conservarSaltos = false) {
  let texto = String(value ?? "").replace(/&nbsp;|&#160;/gi, " ");
  const cp1252 = { "€": 0x80, "‚": 0x82, "ƒ": 0x83, "„": 0x84, "…": 0x85, "†": 0x86, "‡": 0x87, "ˆ": 0x88, "‰": 0x89, "Š": 0x8a, "‹": 0x8b, "Œ": 0x8c, "Ž": 0x8e, "‘": 0x91, "’": 0x92, "“": 0x93, "”": 0x94, "•": 0x95, "–": 0x96, "—": 0x97, "˜": 0x98, "™": 0x99, "š": 0x9a, "›": 0x9b, "œ": 0x9c, "ž": 0x9e, "Ÿ": 0x9f };
  for (let intento = 0; intento < 3 && /Ã|Â|â€|â€™|â€œ|â€�/.test(texto); intento += 1) {
    if ([...texto].some((caracter) => caracter.codePointAt(0) > 255 && cp1252[caracter] === undefined)) break;
    try {
      const bytes = Uint8Array.from([...texto], (caracter) => cp1252[caracter] ?? caracter.charCodeAt(0));
      const reparado = new TextDecoder("utf-8", { fatal: true }).decode(bytes);
      if (reparado === texto) break;
      texto = reparado;
    } catch {
      break;
    }
  }
  texto = texto.replace(/\u00a0/g, " ").replace(/\u200b/g, "").replace(/Â(?=\s|$)/g, "").normalize("NFC");
  return conservarSaltos
    ? texto.split(/\r?\n/).map((linea) => linea.replace(/[^\S\n]+/g, " ").trim()).join("\n").replace(/\n{3,}/g, "\n\n").trim()
    : texto.replace(/\s+/g, " ").trim();
}

const traducciones = {
  "atonement": "Expiación",
  "book of mormon": "Libro de Mormón",
  "covenants": "Convenios",
  "faith": "Fe",
  "gospel": "Evangelio",
  "holy ghost": "Espíritu Santo",
  "jesus christ": "Jesucristo",
  "prayer": "Oración",
  "repentance": "Arrepentimiento",
  "temple": "Templo"
};
const normalizarEtiqueta = (tag) => {
  const limpia = normalizarTextoEspanol(tag);
  return traducciones[limpia.toLowerCase()] ?? limpia;
};

const host = new URL(item.source_url).hostname.replace(/^www\./, "");
const fuentes = {
  "discursosud.com": "Discursos SUD",
  "speeches.byu.edu": "BYU Speeches Español",
  "churchofjesuschrist.org": "Sitio oficial de la Iglesia"
};
const etiquetasBase = {
  "discursosud.com": ["Discursos SUD", "Doctrina"],
  "speeches.byu.edu": ["BYU Speeches", "Devocional"],
  "churchofjesuschrist.org": ["Iglesia de Jesucristo", "Fuente oficial"]
};

const payload = {
  title: normalizarTextoEspanol(item.title),
  author: normalizarTextoEspanol(item.author) || null,
  source_name: normalizarTextoEspanol(item.source_name ?? fuentes[host] ?? host),
  source_url: item.source_url,
  canonical_url: item.canonical_url ?? item.source_url,
  language: "es",
  content_type: item.content_type ?? "text/html",
  published_at: item.published_at ?? null,
  content: normalizarTextoEspanol(item.content, true),
  summary: normalizarTextoEspanol(item.summary, true) || null,
  tags: [...new Set([...(item.tags ?? []), ...(etiquetasBase[host] ?? [])].map(normalizarEtiqueta).filter(Boolean))],
  metadata: {
    ingestion_mode: "n8n_curated_v1",
    is_seed: false,
    ingested_by: "n8n",
    storage_used: false,
    source_site: host,
    extracted_at: item.extracted_at ?? new Date().toISOString(),
    extractor_version: item.extractor_version ?? "n8n-html-regex-v1"
  }
};

return [{ json: { ...item, payload } }];

const preparado = $("Preparar payload para Gospel Library IA").item.json;
const respuesta = $json;
const body =
  respuesta && typeof respuesta.body === "object"
    ? respuesta.body
    : respuesta && typeof respuesta.body === "string"
      ? (() => {
          try { return JSON.parse(respuesta.body); } catch { return {}; }
        })()
      : respuesta;
const httpStatus = Number(respuesta.statusCode ?? respuesta.status ?? 200);

if (preparado.status === "skipped") {
  return [{
    json: {
      resultado: "skipped",
      source_url: preparado.source_url,
      title: preparado.title ?? null,
      mensaje: preparado.razon ?? "Documento omitido por validación."
    }
  }];
}

if (body?.status === "created" || body?.status === "verified_existing") {
  return [{
    json: {
      resultado: body.status,
      source_url: preparado.source_url,
      title: preparado.title,
      document_id: body.document_id,
      chunks: body.chunks,
      mensaje: body.status === "created"
        ? "Documento creado correctamente."
        : "El documento ya existía y fue verificado."
    }
  }];
}

return [{
  json: {
    resultado: httpStatus >= 500 ? "error" : "rejected",
    source_url: preparado.source_url,
    title: preparado.title ?? null,
    mensaje: body?.detail
      ? JSON.stringify(body.detail)
      : `La API respondió HTTP ${httpStatus}.`
  }
}];
